import fs from "fs";
import path from "path";

const outDir = path.join(process.cwd(), "src/data/questions");
fs.mkdirSync(outDir, { recursive: true });

/** @typedef {{id:string,domain:string,prompt:string,choices:[string,string,string,string],correctIndex:0|1|2|3,explanation:string}} Q */

/** @type {Q[]} */
const all = [];

function add(domain, prompt, choices, correctIndex, explanation) {
  const n = all.filter((x) => x.domain === domain).length + 1;
  const prefix =
    domain === "texas-law" ? "txlaw" : domain === "annuity" ? "ann" : domain.slice(0, 4);
  all.push({
    id: `${prefix}-${String(n).padStart(3, "0")}`,
    domain,
    prompt,
    choices,
    correctIndex,
    explanation,
  });
}

function mc(domain, prompt, correct, wrongs, explanation) {
  const choices = [correct, ...wrongs].slice(0, 4);
  // rotate so correct isn't always A
  const rot = all.length % 4;
  const rotated = [...choices.slice(rot), ...choices.slice(0, rot)];
  const correctIndex = rotated.indexOf(correct);
  add(domain, prompt, rotated, correctIndex, explanation);
}

